import React, { useState } from 'react';
import {
  Box,
  Card,
  CardContent,
  Typography,
  IconButton,
  Button,
  Chip,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  TextField,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Grid,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  Divider,
} from '@mui/material';
import {
  ChevronLeft,
  ChevronRight,
  Today,
  Add,
  Event,
  Assignment,
  School,
  Schedule,
} from '@mui/icons-material';
import { CalendarEvent } from '../../types';
import { format, startOfMonth, endOfMonth, eachDayOfInterval, isSameMonth, isSameDay, addMonths, subMonths } from 'date-fns';

interface CalendarProps {
  events: CalendarEvent[];
  onEventClick?: (event: CalendarEvent) => void;
  onCreateEvent?: (event: Omit<CalendarEvent, 'id' | 'createdAt' | 'updatedAt'>) => void;
}

const Calendar: React.FC<CalendarProps> = ({ events, onEventClick, onCreateEvent }) => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [showEventDialog, setShowEventDialog] = useState(false);
  const [newEvent, setNewEvent] = useState({
    title: '',
    description: '',
    start: '',
    end: '',
    type: 'class' as const,
    location: '',
    isAllDay: false,
  });

  const monthStart = startOfMonth(currentDate);
  const monthEnd = endOfMonth(currentDate);
  const calendarDays = eachDayOfInterval({ start: monthStart, end: monthEnd });

  const getEventsForDate = (date: Date) => {
    return events.filter(event => 
      isSameDay(new Date(event.start), date)
    );
  };

  const getEventColor = (type: string) => {
    switch (type) {
      case 'class': return 'primary';
      case 'assignment': return 'warning';
      case 'exam': return 'error';
      case 'holiday': return 'info';
      case 'meeting': return 'success';
      default: return 'default';
    }
  };

  const getEventIcon = (type: string) => {
    switch (type) {
      case 'class': return <School />;
      case 'assignment': return <Assignment />;
      case 'exam': return <Assignment />;
      case 'holiday': return <Event />;
      case 'meeting': return <Schedule />;
      default: return <Event />;
    }
  };

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    setNewEvent(prev => ({
      ...prev,
      start: format(date, 'yyyy-MM-dd'),
      end: format(date, 'yyyy-MM-dd'),
    }));
  };

  const handleCreateEvent = () => {
    if (newEvent.title && newEvent.start) {
      onCreateEvent?.({
        ...newEvent,
        start: newEvent.start,
        end: newEvent.end || newEvent.start,
        color: getEventColor(newEvent.type),
        createdBy: { id: '1', firstName: 'Current', lastName: 'User' } as any,
      });
      setShowEventDialog(false);
      setNewEvent({
        title: '',
        description: '',
        start: '',
        end: '',
        type: 'class',
        location: '',
        isAllDay: false,
      });
    }
  };

  const navigateMonth = (direction: 'prev' | 'next') => {
    setCurrentDate(prev => 
      direction === 'prev' ? subMonths(prev, 1) : addMonths(prev, 1)
    );
  };

  const goToToday = () => {
    setCurrentDate(new Date());
  };

  return (
    <Box>
      {/* Calendar Header */}
      <Card sx={{ mb: 3 }}>
        <CardContent>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
            <Typography variant="h4">
              {format(currentDate, 'MMMM yyyy')}
            </Typography>
            <Box sx={{ display: 'flex', gap: 1 }}>
              <IconButton onClick={() => navigateMonth('prev')}>
                <ChevronLeft />
              </IconButton>
              <Button
                variant="outlined"
                startIcon={<Today />}
                onClick={goToToday}
              >
                Today
              </Button>
              <IconButton onClick={() => navigateMonth('next')}>
                <ChevronRight />
              </IconButton>
            </Box>
          </Box>

          {/* Calendar Grid */}
          <Box sx={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 1 }}>
            {/* Day Headers */}
            {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
              <Box
                key={day}
                sx={{
                  p: 1,
                  textAlign: 'center',
                  fontWeight: 'bold',
                  color: 'text.secondary',
                  backgroundColor: 'grey.100',
                  borderRadius: 1,
                }}
              >
                {day}
              </Box>
            ))}

            {/* Calendar Days */}
            {calendarDays.map((day, index) => {
              const dayEvents = getEventsForDate(day);
              const isCurrentMonth = isSameMonth(day, currentDate);
              const isToday = isSameDay(day, new Date());
              const isSelected = selectedDate && isSameDay(day, selectedDate);

              return (
                <Box
                  key={index}
                  onClick={() => handleDateClick(day)}
                  sx={{
                    minHeight: 100,
                    p: 1,
                    border: '1px solid',
                    borderColor: 'grey.300',
                    borderRadius: 1,
                    cursor: 'pointer',
                    backgroundColor: isSelected ? 'primary.light' : isToday ? 'primary.50' : 'transparent',
                    opacity: isCurrentMonth ? 1 : 0.3,
                    '&:hover': {
                      backgroundColor: 'primary.50',
                    },
                  }}
                >
                  <Typography
                    variant="body2"
                    sx={{
                      fontWeight: isToday ? 'bold' : 'normal',
                      color: isToday ? 'primary.main' : 'text.primary',
                    }}
                  >
                    {format(day, 'd')}
                  </Typography>
                  
                  {/* Events for this day */}
                  <Box sx={{ mt: 0.5 }}>
                    {dayEvents.slice(0, 2).map((event, eventIndex) => (
                      <Chip
                        key={eventIndex}
                        label={event.title}
                        size="small"
                        color={getEventColor(event.type) as any}
                        icon={getEventIcon(event.type)}
                        onClick={(e) => {
                          e.stopPropagation();
                          onEventClick?.(event);
                        }}
                        sx={{
                          fontSize: '0.7rem',
                          height: 20,
                          mb: 0.5,
                          '& .MuiChip-label': {
                            px: 0.5,
                          },
                        }}
                      />
                    ))}
                    {dayEvents.length > 2 && (
                      <Typography variant="caption" color="text.secondary">
                        +{dayEvents.length - 2} more
                      </Typography>
                    )}
                  </Box>
                </Box>
              );
            })}
          </Box>
        </CardContent>
      </Card>

      {/* Selected Date Events */}
      {selectedDate && (
        <Card>
          <CardContent>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
              <Typography variant="h6">
                {format(selectedDate, 'EEEE, MMMM d, yyyy')}
              </Typography>
              <Button
                variant="contained"
                startIcon={<Add />}
                onClick={() => setShowEventDialog(true)}
              >
                Add Event
              </Button>
            </Box>

            <List>
              {getEventsForDate(selectedDate).map((event) => (
                <ListItem
                  key={event.id}
                  button
                  onClick={() => onEventClick?.(event)}
                  sx={{
                    border: '1px solid',
                    borderColor: 'grey.300',
                    borderRadius: 1,
                    mb: 1,
                  }}
                >
                  <ListItemIcon>
                    {getEventIcon(event.type)}
                  </ListItemIcon>
                  <ListItemText
                    primary={event.title}
                    secondary={
                      <Box>
                        <Typography variant="body2" color="text.secondary">
                          {format(new Date(event.start), 'h:mm a')} - {format(new Date(event.end), 'h:mm a')}
                        </Typography>
                        {event.location && (
                          <Typography variant="body2" color="text.secondary">
                            📍 {event.location}
                          </Typography>
                        )}
                        {event.description && (
                          <Typography variant="body2" color="text.secondary">
                            {event.description}
                          </Typography>
                        )}
                      </Box>
                    }
                  />
                  <Chip
                    label={event.type}
                    size="small"
                    color={getEventColor(event.type) as any}
                  />
                </ListItem>
              ))}
              {getEventsForDate(selectedDate).length === 0 && (
                <Typography variant="body2" color="text.secondary" sx={{ textAlign: 'center', py: 2 }}>
                  No events for this date
                </Typography>
              )}
            </List>
          </CardContent>
        </Card>
      )}

      {/* Create Event Dialog */}
      <Dialog open={showEventDialog} onClose={() => setShowEventDialog(false)} maxWidth="sm" fullWidth>
        <DialogTitle>Create New Event</DialogTitle>
        <DialogContent>
          <Grid container spacing={2} sx={{ mt: 1 }}>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Event Title"
                value={newEvent.title}
                onChange={(e) => setNewEvent(prev => ({ ...prev, title: e.target.value }))}
              />
            </Grid>
            <Grid item xs={12}>
              <TextField
                fullWidth
                label="Description"
                multiline
                rows={3}
                value={newEvent.description}
                onChange={(e) => setNewEvent(prev => ({ ...prev, description: e.target.value }))}
              />
            </Grid>
            <Grid item xs={6}>
              <TextField
                fullWidth
                label="Start Date"
                type="date"
                value={newEvent.start}
                onChange={(e) => setNewEvent(prev => ({ ...prev, start: e.target.value }))}
                InputLabelProps={{ shrink: true }}
              />
            </Grid>
            <Grid item xs={6}>
              <TextField
                fullWidth
                label="End Date"
                type="date"
                value={newEvent.end}
                onChange={(e) => setNewEvent(prev => ({ ...prev, end: e.target.value }))}
                InputLabelProps={{ shrink: true }}
              />
            </Grid>
            <Grid item xs={6}>
              <FormControl fullWidth>
                <InputLabel>Event Type</InputLabel>
                <Select
                  value={newEvent.type}
                  label="Event Type"
                  onChange={(e) => setNewEvent(prev => ({ ...prev, type: e.target.value as any }))}
                >
                  <MenuItem value="class">Class</MenuItem>
                  <MenuItem value="assignment">Assignment</MenuItem>
                  <MenuItem value="exam">Exam</MenuItem>
                  <MenuItem value="holiday">Holiday</MenuItem>
                  <MenuItem value="meeting">Meeting</MenuItem>
                </Select>
              </FormControl>
            </Grid>
            <Grid item xs={6}>
              <TextField
                fullWidth
                label="Location"
                value={newEvent.location}
                onChange={(e) => setNewEvent(prev => ({ ...prev, location: e.target.value }))}
              />
            </Grid>
          </Grid>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setShowEventDialog(false)}>Cancel</Button>
          <Button onClick={handleCreateEvent} variant="contained">
            Create Event
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
};

export default Calendar;
